import React, { useRef, useEffect, useState } from 'react';
import { AppState, IconAdjusterData, IconItem, IconOverlay } from '../../types';
import { TRANSLATIONS } from '../../translations';
import { UploadIcon, DownloadAllIcon, CloseIcon, DeleteIcon, FileIcon } from '../../components/Icons';
import JSZip from 'jszip';

interface Props {
  state: AppState;
  handleIconUpload: (files: FileList) => void;
  updateIconAdjusterData: (updates: Partial<IconAdjusterData>) => void;
  updateIconItem: (idOrIds: string | string[], updates: Partial<IconItem>) => void;
}

const SingleIconCanvas: React.FC<{ 
    item: IconItem; 
    data: IconAdjusterData; 
    isSelected: boolean;
    onSelect: (e: React.MouseEvent) => void;
    onDelete: () => void;
}> = ({ item, data, isSelected, onSelect, onDelete }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const loadImg = (src: string) => new Promise<HTMLImageElement | null>((resolve) => {
            const img = new Image();
            img.crossOrigin = "Anonymous";
            img.onload = () => resolve(img);
            img.onerror = () => {
                console.warn("Failed to load image:", src);
                resolve(null);
            };
            img.src = src;
        });

        const render = async () => {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            if (data.background === 'white') {
                ctx.fillStyle = '#ffffff';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
            } else if (data.background === 'black') {
                ctx.fillStyle = '#000000';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
            } else if (data.background === 'custom') {
                ctx.fillStyle = data.backgroundColor;
                ctx.fillRect(0, 0, canvas.width, canvas.height);
            }

            try {
                const [img, overlayImg] = await Promise.all([
                    loadImg(item.src),
                    item.overlay ? loadImg(item.overlay.src) : Promise.resolve(null)
                ]);

                if (!img) return;

                const centerX = canvas.width / 2 + item.x;
                const centerY = canvas.height / 2 + item.y;
                const dw = img.naturalWidth * item.scale;
                const dh = img.naturalHeight * item.scale;
                const dx = centerX - dw / 2;
                const dy = centerY - dh / 2;

                if (data.strokeEnabled && data.strokeThickness > 0) {
                    ctx.save();
                    const thick = data.strokeThickness;
                    const steps = data.strokeSmoothness || 8;

                    ctx.shadowColor = data.strokeColor;
                    ctx.shadowBlur = data.strokeBlur || 0;

                    const offsets = [];
                    for (let i = 0; i < steps; i++) {
                        const angle = (i / steps) * 2 * Math.PI;
                        offsets.push([Math.cos(angle) * thick, Math.sin(angle) * thick]);
                    }

                    offsets.forEach(([ox, oy]) => {
                       ctx.shadowOffsetX = ox;
                       ctx.shadowOffsetY = oy;
                       ctx.drawImage(img, dx, dy, dw, dh);
                    });

                    ctx.restore();
                }

                ctx.drawImage(img, dx, dy, dw, dh);

                if (overlayImg && item.overlay) {
                    ctx.save();
                    ctx.translate(canvas.width / 2, canvas.height / 2);
                    ctx.translate(item.overlay.x, item.overlay.y);
                    ctx.rotate((item.overlay.rotation || 0) * Math.PI / 180);
                    ctx.scale(item.overlay.scale, item.overlay.scale);
                    ctx.drawImage(overlayImg, -overlayImg.naturalWidth / 2, -overlayImg.naturalHeight / 2);
                    ctx.restore();
                }

                if (data.fitPadding > 0) {
                    ctx.save();
                    ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
                    ctx.lineWidth = 1;
                    ctx.setLineDash([5, 5]);
                    const p = data.fitPadding;
                    ctx.strokeRect(p, p, canvas.width - p * 2, canvas.height - p * 2);
                    ctx.restore();
                }

            } catch (e) {
                console.error("Render error", e);
            }
        };

        render();

    }, [item, data]); 

    const checkerColor = data.checkeredMode === 'light' ? '#e4e4e7' : '#1f1f22';
    const checkerBg = data.checkeredMode === 'light' ? '#ffffff' : 'transparent';

    return (
        <div 
            className={`relative group flex flex-col gap-2 p-1 border-2 rounded-xl overflow-hidden transition-all duration-300 ${isSelected ? 'border-indigo-500 shadow-lg shadow-indigo-500/20 ring-1 ring-indigo-500 scale-[1.02] bg-indigo-500/5' : 'border-zinc-800/50 hover:border-zinc-600 hover:bg-zinc-800/20'}`}
            onClick={onSelect}
        >
            <div className="relative aspect-square overflow-hidden rounded-lg">
                <canvas 
                    ref={canvasRef} 
                    width={data.canvasWidth} 
                    height={data.canvasHeight} 
                    className="w-full h-auto"
                    style={{
                        backgroundColor: data.background === 'transparent' ? checkerBg : 'transparent',
                        backgroundImage: data.background === 'transparent' ? `linear-gradient(45deg, ${checkerColor} 25%, transparent 25%), linear-gradient(-45deg, ${checkerColor} 25%, transparent 25%), linear-gradient(45deg, transparent 75%, ${checkerColor} 75%), linear-gradient(-45deg, transparent 75%, ${checkerColor} 75%)` : 'none',
                        backgroundSize: '16px 16px',
                        backgroundPosition: '0 0, 0 8px, 8px -8px, -8px 0px'
                    }}
                />
                <button onClick={(e) => { e.stopPropagation(); onDelete(); }} className="absolute top-2 right-2 bg-black/60 hover:bg-red-500 text-white rounded-full p-1.5 opacity-0 group-hover:opacity-100 transition shadow-lg z-10"><CloseIcon className="w-3.5 h-3.5" /></button>
            </div>
            <div className={`px-2 pb-1 text-[10px] font-medium text-center truncate ${isSelected ? 'text-indigo-300' : 'text-zinc-500 group-hover:text-zinc-300'} transition-colors duration-300`}>
                {item.file.name}
            </div>
        </div>
    );
};

const IconAdjuster: React.FC<Props> = ({ state, handleIconUpload, updateIconAdjusterData, updateIconItem }) => {
  const data = state.iconAdjusterData;
  const t = TRANSLATIONS[state.language];
  const fileInputRef = useRef<HTMLInputElement>(null);
  const overlayInputRef = useRef<HTMLInputElement>(null);
  const [lastClickedId, setLastClickedId] = useState<string | null>(null);

  const getSortedItems = () => {
    const items = [...data.items];
    switch (data.sortOrder) {
        case 'name_asc':
            return items.sort((a, b) => a.file.name.localeCompare(b.file.name));
        case 'name_desc':
            return items.sort((a, b) => b.file.name.localeCompare(a.file.name));
        case 'newest':
            return items.sort((a, b) => parseFloat(b.id) - parseFloat(a.id));
        case 'oldest':
            return items.sort((a, b) => parseFloat(a.id) - parseFloat(b.id));
        case 'original':
        default:
            return items;
    }
  };

  const sortedItems = getSortedItems();

  const getTargetIds = () => {
      if (data.commandMode === 'all') {
          return data.items.map(i => i.id);
      }
      return data.selectedItemIds;
  };

  const primarySelectedItem = data.items.find(i => i.id === data.selectedItemIds[0]);

  const handleOverlayUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const targetIds = getTargetIds();
      if (targetIds.length === 0) {
          alert("Select at least one item to add overlay.");
          return;
      }

      const url = URL.createObjectURL(file);
      const newOverlay: IconOverlay = {
          src: url,
          x: 0,
          y: 0,
          scale: 1,
          rotation: 0
      };

      updateIconItem(targetIds, { overlay: newOverlay });
      e.target.value = '';
  };

  const updateOverlayProp = (key: keyof IconOverlay, value: number) => {
      const targetIds = getTargetIds();
      const newItems = data.items.map(item => {
          if (targetIds.includes(item.id) && item.overlay) {
              return {
                  ...item,
                  overlay: { ...item.overlay, [key]: value }
              };
          }
          return item;
      });
      updateIconAdjusterData({ items: newItems });
  };

  const removeOverlay = () => {
      const targetIds = getTargetIds();
      const newItems = data.items.map(item => {
          if (targetIds.includes(item.id)) {
              const { overlay, ...rest } = item;
              return rest;
          }
          return item;
      });
      updateIconAdjusterData({ items: newItems });
  };

  const calculateCrop = (item: IconItem): Promise<Partial<IconItem> | null> => {
      return new Promise((resolve) => {
          const img = new Image();
          img.crossOrigin = "Anonymous";
          img.src = item.src;
          img.onload = () => {
              const cvs = document.createElement('canvas');
              cvs.width = img.naturalWidth;
              cvs.height = img.naturalHeight;
              const ctx = cvs.getContext('2d');
              if(!ctx) { resolve(null); return; }
              ctx.drawImage(img, 0, 0);
              const pixels = ctx.getImageData(0,0, cvs.width, cvs.height).data;

              let minX = cvs.width, minY = cvs.height, maxX = 0, maxY = 0;
              let found = false;

              for(let y=0; y<cvs.height; y++) {
                  for(let x=0; x<cvs.width; x++) {
                      const alpha = pixels[(y*cvs.width + x)*4 + 3];
                      if(alpha > data.cropThreshold) {
                          if(x < minX) minX = x;
                          if(x > maxX) maxX = x;
                          if(y < minY) minY = y;
                          if(y > maxY) maxY = y;
                          found = true;
                      }
                  }
              }

              if(!found) { resolve(null); return; }

              const bw = maxX - minX + 1;
              const bh = maxY - minY + 1;
              const cx = minX + bw / 2;
              const cy = minY + bh / 2;

              const ox = img.naturalWidth / 2;
              const oy = img.naturalHeight / 2;
              const vx = cx - ox;
              const vy = cy - oy;

              const availableW = data.canvasWidth - (data.fitPadding * 2);
              const availableH = data.canvasHeight - (data.fitPadding * 2);
              const scaleW = availableW / bw;
              const scaleH = availableH / bh;
              const newScale = Math.min(scaleW, scaleH);

              resolve({
                  scale: newScale,
                  x: -vx * newScale,
                  y: -vy * newScale
              });
          };
          img.onerror = () => resolve(null);
      });
  };

  useEffect(() => {
    const handleKeyDown = async (e: KeyboardEvent) => {
        const targetIds = getTargetIds();
        if (targetIds.length === 0) return;

        const move = data.moveStep;
        const scaleStep = data.scaleStep;
        const key = e.key.toLowerCase();

        if (['w','a','s','d','q','e','r'].includes(key)) {
            e.preventDefault();
        }

        let hasChanges = false;
        let newItems = data.items.map(item => {
             if (targetIds.includes(item.id)) {
                 let updates: Partial<IconItem> | null = null;
                 switch(key) {
                    case 'w': updates = { y: item.y - move }; break;
                    case 's': updates = { y: item.y + move }; break;
                    case 'a': updates = { x: item.x - move }; break;
                    case 'd': updates = { x: item.x + move }; break;
                    case 'q': updates = { scale: Math.max(0.01, item.scale - scaleStep) }; break;
                    case 'e': updates = { scale: item.scale + scaleStep }; break;
                 }
                 if (updates) {
                     hasChanges = true;
                     return { ...item, ...updates };
                 }
             }
             return item;
        });

        if (key === 'r') {
             const targetItems = data.items.filter(item => targetIds.includes(item.id));
             if (targetItems.length === 0) return;

             const results = await Promise.all(targetItems.map(async (item) => {
                 const updates = await calculateCrop(item);
                 return { id: item.id, updates };
             }));

             newItems = data.items.map(item => {
                 const res = results.find(r => r.id === item.id);
                 if (res && res.updates) {
                     return { ...item, ...res.updates };
                 }
                 return item;
             });
             updateIconAdjusterData({ items: newItems });

        } else if (hasChanges) {
             updateIconAdjusterData({ items: newItems });
        }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [data.selectedItemIds, data.commandMode, data.items, data.moveStep, data.scaleStep, data.canvasWidth, data.canvasHeight, data.fitPadding, data.cropThreshold]);

  const handleItemClick = (id: string, e: React.MouseEvent) => {
      if (data.commandMode === 'one') {
          updateIconAdjusterData({ selectedItemIds: [id] });
          setLastClickedId(id);
      } else if (data.commandMode === 'multi') {
          if (e.shiftKey && lastClickedId) {
              const idx1 = sortedItems.findIndex(i => i.id === lastClickedId);
              const idx2 = sortedItems.findIndex(i => i.id === id);
              if (idx1 !== -1 && idx2 !== -1) {
                  const start = Math.min(idx1, idx2);
                  const end = Math.max(idx1, idx2);
                  const rangeIds = sortedItems.slice(start, end + 1).map(i => i.id);
                  const newSelection = Array.from(new Set([...data.selectedItemIds, ...rangeIds]));
                  updateIconAdjusterData({ selectedItemIds: newSelection });
              }
          } else if (e.altKey && lastClickedId) {
              const idx1 = sortedItems.findIndex(i => i.id === lastClickedId);
              const idx2 = sortedItems.findIndex(i => i.id === id);
              if (idx1 !== -1 && idx2 !== -1) {
                  const start = Math.min(idx1, idx2);
                  const end = Math.max(idx1, idx2);
                  const rangeIdsToRemove = sortedItems.slice(start, end + 1).map(i => i.id);
                  const newSelection = data.selectedItemIds.filter(sid => !rangeIdsToRemove.includes(sid));
                  updateIconAdjusterData({ selectedItemIds: newSelection });
              }
          } else {
              if (data.selectedItemIds.includes(id)) {
                  updateIconAdjusterData({ selectedItemIds: data.selectedItemIds.filter(sid => sid !== id) });
              } else {
                  updateIconAdjusterData({ selectedItemIds: [...data.selectedItemIds, id] });
              }
          }
          setLastClickedId(id);
      } else {
          updateIconAdjusterData({ selectedItemIds: [id], commandMode: 'one' });
          setLastClickedId(id);
      }
  };

  const isItemSelected = (id: string) => {
      if (data.commandMode === 'all') return true;
      return data.selectedItemIds.includes(id);
  };

  const renderItemToCanvas = (item: IconItem, ctx: CanvasRenderingContext2D) => {
      return new Promise<void>(async (resolve) => {
          const loadImg = (src: string) => new Promise<HTMLImageElement | null>((resolve) => {
              const img = new Image();
              img.crossOrigin = "Anonymous";
              img.onload = () => resolve(img);
              img.onerror = () => resolve(null);
              img.src = src;
          });

          ctx.clearRect(0, 0, data.canvasWidth, data.canvasHeight);

          if (data.background === 'white') {
              ctx.fillStyle = '#ffffff';
              ctx.fillRect(0, 0, data.canvasWidth, data.canvasHeight);
          } else if (data.background === 'black') {
              ctx.fillStyle = '#000000';
              ctx.fillRect(0, 0, data.canvasWidth, data.canvasHeight);
          } else if (data.background === 'custom') {
              ctx.fillStyle = data.backgroundColor;
              ctx.fillRect(0, 0, data.canvasWidth, data.canvasHeight);
          }

          try {
              const [img, overlayImg] = await Promise.all([
                  loadImg(item.src),
                  item.overlay ? loadImg(item.overlay.src) : Promise.resolve(null)
              ]);

              if (!img) { resolve(); return; }

              const centerX = data.canvasWidth / 2 + item.x;
              const centerY = data.canvasHeight / 2 + item.y;
              const dw = img.naturalWidth * item.scale;
              const dh = img.naturalHeight * item.scale;
              const dx = centerX - dw / 2;
              const dy = centerY - dh / 2;

              if (data.strokeEnabled && data.strokeThickness > 0) {
                  ctx.save();
                  const thick = data.strokeThickness;
                  const steps = data.strokeSmoothness || 8;
                  ctx.shadowColor = data.strokeColor;
                  ctx.shadowBlur = data.strokeBlur || 0;
                  const offsets = [];
                  for (let i = 0; i < steps; i++) {
                      const angle = (i / steps) * 2 * Math.PI;
                      offsets.push([Math.cos(angle) * thick, Math.sin(angle) * thick]);
                  }
                  offsets.forEach(([ox, oy]) => {
                      ctx.shadowOffsetX = ox; ctx.shadowOffsetY = oy;
                      ctx.drawImage(img, dx, dy, dw, dh);
                  });
                  ctx.restore();
              }
              ctx.drawImage(img, dx, dy, dw, dh);

              if (overlayImg && item.overlay) {
                  ctx.save();
                  ctx.translate(data.canvasWidth / 2, data.canvasHeight / 2);
                  ctx.translate(item.overlay.x, item.overlay.y);
                  ctx.rotate((item.overlay.rotation || 0) * Math.PI / 180);
                  ctx.scale(item.overlay.scale, item.overlay.scale);
                  ctx.drawImage(overlayImg, -overlayImg.naturalWidth / 2, -overlayImg.naturalHeight / 2);
                  ctx.restore();
              }
              resolve();
          } catch (e) { resolve(); }
      });
  };

  const handleSaveZip = async () => {
      const zip = new JSZip();
      const tempCanvas = document.createElement('canvas');
      tempCanvas.width = data.canvasWidth;
      tempCanvas.height = data.canvasHeight;
      const ctx = tempCanvas.getContext('2d');
      if (!ctx) return;

      for (const item of data.items) {
          await renderItemToCanvas(item, ctx);
          const base64Data = tempCanvas.toDataURL('image/png').split(',')[1];
          const originalName = item.file.name.replace(/\.[^/.]+$/, "");
          zip.file(`${originalName}.png`, base64Data, { base64: true });
      }

      const content = await zip.generateAsync({ type: "blob" });
      const url = URL.createObjectURL(content);
      const link = document.createElement('a');
      link.href = url;
      link.download = "sandria_icons.zip";
      link.click();
  };

  const handleClearAll = () => {
      // Direct clear without confirmation as per user request to fix "not working" issue
      updateIconAdjusterData({ items: [], selectedItemIds: [] });
  };

  const gridPercent = Math.round(((11 - data.gridColumns) / 9) * 100);

  return (
    <div className="flex flex-col md:flex-row h-full overflow-hidden animate-fade-in-up">
        {/* Sidebar Settings */}
        <div className="w-full md:w-80 bg-zinc-900/50 backdrop-blur-md border-r border-zinc-800 p-6 overflow-y-auto custom-scrollbar flex flex-col gap-6">
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <span className="text-blue-400">🖼️</span> {t.iconAdjuster.title}
            </h2>

            <div 
                className="w-full aspect-video border-2 border-dashed border-zinc-700/50 bg-zinc-950/30 rounded-xl hover:border-blue-500/50 hover:bg-blue-500/5 transition flex flex-col items-center justify-center cursor-pointer group"
                onClick={() => fileInputRef.current?.click()}
            >
                <input type="file" ref={fileInputRef} multiple accept="image/*" className="hidden" onChange={(e) => e.target.files && handleIconUpload(e.target.files)} />
                <UploadIcon className="w-8 h-8 text-zinc-600 group-hover:text-blue-400 mb-2 transition" />
                <p className="text-xs font-bold text-zinc-400">{t.iconAdjuster.uploadTitle}</p>
                <p className="text-[10px] text-zinc-600">{t.iconAdjuster.uploadDesc}</p>
            </div>

            <div className="h-px bg-zinc-800" />

            {/* Selection Mode */}
            <div className="space-y-2">
                <label className="text-xs font-bold text-zinc-500 uppercase tracking-wider">{t.iconAdjuster.selectionMode}</label>
                <div className="flex bg-zinc-950 p-1 rounded-lg border border-zinc-800">
                    {['all', 'one', 'multi'].map(mode => (
                        <button 
                            key={mode}
                            onClick={() => updateIconAdjusterData({ commandMode: mode as any })}
                            className={`flex-1 py-2 text-xs font-bold rounded-md transition-all ${data.commandMode === mode ? 'bg-zinc-800 text-white shadow-sm' : 'text-zinc-500 hover:text-zinc-300'}`}
                        >
                            {mode === 'one' ? t.iconAdjuster.modeOne : mode === 'multi' ? t.iconAdjuster.modeMulti : t.iconAdjuster.modeAll}
                        </button>
                    ))}
                </div>
            </div>

            <div className="h-px bg-zinc-800" />

            {/* Overlay Settings */}
            <div className="space-y-4">
                 <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-wider">{t.iconAdjuster.overlayTitle}</h4>

                 <div className="flex gap-2">
                     <button 
                        onClick={() => overlayInputRef.current?.click()}
                        className="flex-1 py-2 bg-zinc-800 hover:bg-zinc-700 text-zinc-300 rounded-lg text-xs font-medium transition flex items-center justify-center gap-2"
                     >
                         <UploadIcon className="w-3 h-3" /> {t.iconAdjuster.overlayUpload}
                     </button>
                     <input type="file" ref={overlayInputRef} accept="image/*" className="hidden" onChange={handleOverlayUpload} />
                     {primarySelectedItem?.overlay && (
                         <button onClick={removeOverlay} className="p-2 bg-red-900/30 hover:bg-red-900/50 text-red-400 rounded-lg transition">
                             <DeleteIcon className="w-4 h-4" />
                         </button>
                     )}
                 </div>

                 {primarySelectedItem?.overlay && (
                     <div className="space-y-3 pl-4 border-l border-zinc-800 animate-fade-in">
                         <div className="space-y-1">
                             <label className="text-[10px] text-zinc-400">{t.iconAdjuster.overlayX}</label>
                             <input type="range" min="-200" max="200" value={primarySelectedItem.overlay.x} onChange={(e) => updateOverlayProp('x', parseInt(e.target.value))} className="w-full h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-blue-500" />
                         </div>
                         <div className="space-y-1">
                             <label className="text-[10px] text-zinc-400">{t.iconAdjuster.overlayY}</label>
                             <input type="range" min="-200" max="200" value={primarySelectedItem.overlay.y} onChange={(e) => updateOverlayProp('y', parseInt(e.target.value))} className="w-full h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-blue-500" />
                         </div>
                         <div className="space-y-1">
                             <label className="text-[10px] text-zinc-400">{t.iconAdjuster.overlayScale}</label>
                             <input type="range" min="0.1" max="3" step="0.1" value={primarySelectedItem.overlay.scale} onChange={(e) => updateOverlayProp('scale', parseFloat(e.target.value))} className="w-full h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-blue-500" />
                         </div>
                         <div className="space-y-1">
                             <label className="text-[10px] text-zinc-400">{t.iconAdjuster.overlayRotate}</label>
                             <input type="range" min="0" max="360" value={primarySelectedItem.overlay.rotation} onChange={(e) => updateOverlayProp('rotation', parseInt(e.target.value))} className="w-full h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-blue-500" />
                         </div>
                     </div>
                 )}
            </div>

            <div className="h-px bg-zinc-800" />

            {/* Canvas Settings */}
            <div className="space-y-4">
                 <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-wider">{t.iconAdjuster.canvasSettings}</h4>
                 <div className="grid grid-cols-2 gap-3">
                     <div className="space-y-1">
                         <label className="text-[10px] text-zinc-400">Width</label>
                         <input type="number" value={data.canvasWidth} onChange={(e) => updateIconAdjusterData({ canvasWidth: parseInt(e.target.value) })} className="w-full bg-zinc-950 border border-zinc-700 rounded p-2 text-sm text-zinc-200" />
                     </div>
                     <div className="space-y-1">
                         <label className="text-[10px] text-zinc-400">Height</label>
                         <input type="number" value={data.canvasHeight} onChange={(e) => updateIconAdjusterData({ canvasHeight: parseInt(e.target.value) })} className="w-full bg-zinc-950 border border-zinc-700 rounded p-2 text-sm text-zinc-200" />
                     </div>
                 </div>
                 <div className="space-y-1">
                     <label className="text-[10px] text-zinc-400">{t.iconAdjuster.padding}</label>
                     <input type="number" value={data.fitPadding} onChange={(e) => updateIconAdjusterData({ fitPadding: parseInt(e.target.value) })} className="w-full bg-zinc-950 border border-zinc-700 rounded p-2 text-sm text-zinc-200" />
                 </div>
                 <div className="space-y-2">
                     <label className="text-[10px] text-zinc-400">{t.iconAdjuster.bg}</label>
                     <select value={data.background} onChange={(e) => updateIconAdjusterData({ background: e.target.value as any })} className="w-full bg-zinc-950 border border-zinc-700 rounded p-2 text-sm outline-none text-zinc-200">
                         <option value="transparent">{t.iconAdjuster.bgTransparent}</option>
                         <option value="white">{t.iconAdjuster.bgWhite}</option>
                         <option value="black">{t.iconAdjuster.bgBlack}</option>
                         <option value="custom">{t.iconAdjuster.bgCustom}</option>
                     </select>

                     {/* Checkered Mode Toggle - Reordered */}
                     {data.background === 'transparent' && (
                         <div className="space-y-2 mt-2 animate-fade-in">
                            <label className="text-[10px] text-zinc-500 uppercase font-bold tracking-tight">{t.iconAdjuster.checkeredTitle}</label>
                            <div className="flex bg-zinc-950 p-1 rounded-lg border border-zinc-800">
                                <button 
                                    onClick={() => updateIconAdjusterData({ checkeredMode: 'light' })} 
                                    className={`flex-1 py-1.5 text-[10px] font-bold rounded transition-all ${data.checkeredMode === 'light' ? 'bg-zinc-100 text-zinc-900 shadow-sm' : 'text-zinc-600 hover:text-zinc-400'}`}
                                >
                                    {t.iconAdjuster.checkeredLight}
                                </button>
                                <button 
                                    onClick={() => updateIconAdjusterData({ checkeredMode: 'dark' })} 
                                    className={`flex-1 py-1.5 text-[10px] font-bold rounded transition-all ${data.checkeredMode === 'dark' ? 'bg-zinc-800 text-white shadow-sm' : 'text-zinc-600 hover:text-zinc-400'}`}
                                >
                                    {t.iconAdjuster.checkeredDark}
                                </button>
                            </div>
                         </div>
                     )}

                     {data.background === 'custom' && (
                         <div className="flex items-center gap-2">
                             <input type="color" value={data.backgroundColor} onChange={(e) => updateIconAdjusterData({ backgroundColor: e.target.value })} className="w-8 h-8 rounded border-none cursor-pointer" />
                             <span className="text-xs text-zinc-400">{data.backgroundColor}</span>
                         </div>
                     )}
                 </div>
            </div>

            <div className="h-px bg-zinc-800" />

            {/* Stroke Settings */}
            <div className="space-y-4">
                 <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-wider">{t.iconAdjuster.strokeTitle}</h4>
                 <label className="flex items-center gap-2 text-sm text-zinc-300">
                     <input type="checkbox" checked={data.strokeEnabled} onChange={(e) => updateIconAdjusterData({ strokeEnabled: e.target.checked })} className="rounded bg-zinc-800 border-zinc-700 text-blue-500" />
                     {t.iconAdjuster.enableStroke}
                 </label>
                 {data.strokeEnabled && (
                     <div className="space-y-3 pl-4 border-l border-zinc-800">
                         <div className="space-y-1">
                             <label className="text-[10px] text-zinc-400">{t.iconAdjuster.color}</label>
                             <div className="flex items-center gap-2">
                                 <input type="color" value={data.strokeColor} onChange={(e) => updateIconAdjusterData({ strokeColor: e.target.value })} className="w-6 h-6 rounded bg-transparent cursor-pointer" />
                                 <span className="text-xs text-zinc-500">{data.strokeColor}</span>
                             </div>
                         </div>
                         <div className="space-y-1">
                             <label className="text-[10px] text-zinc-400">{t.iconAdjuster.thickness}: {data.strokeThickness}px</label>
                             <input type="range" min="1" max="20" value={data.strokeThickness} onChange={(e) => updateIconAdjusterData({ strokeThickness: parseInt(e.target.value) })} className="w-full h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-blue-500" />
                         </div>
                         <div className="space-y-1">
                             <label className="text-[10px] text-zinc-400">{t.iconAdjuster.strokeSmoothness}: {data.strokeSmoothness}</label>
                             <input type="range" min="4" max="64" value={data.strokeSmoothness} onChange={(e) => updateIconAdjusterData({ strokeSmoothness: parseInt(e.target.value) })} className="w-full h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-blue-500" />
                         </div>
                         <div className="space-y-1">
                             <label className="text-[10px] text-zinc-400">{t.iconAdjuster.strokeBlur}: {data.strokeBlur}px</label>
                             <input type="range" min="0" max="20" value={data.strokeBlur} onChange={(e) => updateIconAdjusterData({ strokeBlur: parseInt(e.target.value) })} className="w-full h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-blue-500" />
                         </div>
                     </div>
                 )}
            </div>

            <div className="h-px bg-zinc-800" />

            {/* Controls */}
            <div className="space-y-4">
                 <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-wider">{t.iconAdjuster.controlsTitle}</h4>
                 <div className="bg-zinc-950/50 p-3 rounded-lg text-[10px] text-zinc-400 space-y-1 font-mono border border-zinc-800">
                     <p>{t.iconAdjuster.hotkeys.move}</p>
                     <p>{t.iconAdjuster.hotkeys.scale}</p>
                     <p className="text-teal-400">{t.iconAdjuster.hotkeys.crop}</p>
                 </div>
                 <div className="space-y-2">
                     <label className="text-[10px] text-zinc-400">{t.iconAdjuster.cropThreshold} ({data.cropThreshold})</label>
                     <input type="range" min="0" max="255" value={data.cropThreshold} onChange={(e) => updateIconAdjusterData({ cropThreshold: parseInt(e.target.value) })} className="w-full h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-teal-500" />
                 </div>
                 <div className="space-y-2">
                     <label className="text-[10px] text-zinc-400">{t.iconAdjuster.moveStep}</label>
                     <input type="range" min="1" max="50" value={data.moveStep} onChange={(e) => updateIconAdjusterData({ moveStep: parseInt(e.target.value) })} className="w-full h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-blue-500" />
                 </div>
                 <div className="space-y-2">
                     <label className="text-[10px] text-zinc-400">{t.iconAdjuster.scaleStep}</label>
                     <input type="range" min="0.01" max="1" step="0.01" value={data.scaleStep} onChange={(e) => updateIconAdjusterData({ scaleStep: parseFloat(e.target.value) })} className="w-full h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-blue-500" />
                 </div>
            </div>

            <div className="flex flex-col gap-3 mt-auto">
                <button onClick={handleSaveZip} disabled={data.items.length === 0} className="w-full py-3 bg-teal-600 hover:bg-teal-500 text-white rounded-xl font-bold shadow-lg shadow-teal-900/20 transition flex items-center justify-center gap-2 text-xs">
                    <FileIcon className="w-4 h-4" /> {t.iconAdjuster.saveZip}
                </button>
                {data.items.length > 0 && (
                    <button type="button" onClick={handleClearAll} className="w-full py-2 border border-red-900/50 text-red-400 hover:bg-red-900/20 rounded-lg text-xs font-medium transition flex items-center justify-center gap-2">
                        <DeleteIcon className="w-3 h-3" /> {t.iconAdjuster.clearAll}
                    </button>
                )}
            </div>
        </div>

        {/* Main Grid Area */}
        <div className="flex-1 flex flex-col min-w-0">
            {/* Top Toolbar */}
            <div className="h-16 px-6 md:px-8 border-b border-zinc-800/50 flex items-center justify-between shrink-0 bg-zinc-900/30">
                <div className="text-sm font-medium text-zinc-400 flex items-center gap-2">
                    <span className="hidden md:inline">Items:</span> <span className="text-white font-bold">{data.items.length}</span>
                </div>

                {/* Right Controls Area */}
                <div className="flex items-center gap-3">
                    {/* Sorting Control */}
                    <div className="flex items-center gap-3 bg-zinc-950/50 px-4 py-2 rounded-full border border-zinc-800/50 backdrop-blur-md">
                        <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">{t.iconAdjuster.sortTitle}</span>
                        <select 
                            value={data.sortOrder} 
                            onChange={(e) => updateIconAdjusterData({ sortOrder: e.target.value as any })} 
                            className="bg-transparent text-xs font-bold text-zinc-200 outline-none cursor-pointer hover:text-white transition"
                        >
                            <option value="original" className="bg-zinc-900">{t.iconAdjuster.sortOriginal}</option>
                            <option value="name_asc" className="bg-zinc-900">{t.iconAdjuster.sortNameAsc}</option>
                            <option value="name_desc" className="bg-zinc-900">{t.iconAdjuster.sortNameDesc}</option>
                            <option value="newest" className="bg-zinc-900">{t.iconAdjuster.sortNewest}</option>
                            <option value="oldest" className="bg-zinc-900">{t.iconAdjuster.sortOldest}</option>
                        </select>
                    </div>

                    {/* Grid Zoom Control */}
                    <div className="flex items-center gap-4 bg-zinc-950/50 px-4 py-2 rounded-full border border-zinc-800/50 backdrop-blur-md">
                        <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest">{t.iconAdjuster.gridCols}</span>
                        <div className="flex items-center gap-3 w-32 md:w-48">
                            <input 
                                type="range" 
                                min="2" 
                                max="10" 
                                step="1"
                                value={data.gridColumns || 5} 
                                onChange={(e) => updateIconAdjusterData({ gridColumns: parseInt(e.target.value) })} 
                                className="flex-1 h-1 bg-zinc-800 rounded-full appearance-none cursor-pointer accent-blue-500" 
                            />
                            <span className="text-xs font-mono text-blue-400 w-8 text-right">{gridPercent}%</span>
                        </div>
                    </div>
                </div>
            </div>

            <div className="flex-1 p-6 md:p-10 overflow-y-auto custom-scrollbar">
                {data.items.length === 0 ? (
                    <div className="h-full flex items-center justify-center text-zinc-500 flex-col gap-6 animate-fadeIn">
                        <div className="w-24 h-24 bg-gradient-to-br from-zinc-800 to-zinc-900 rounded-3xl flex items-center justify-center shadow-2xl border border-zinc-700/30">
                            <UploadIcon className="w-10 h-10 opacity-30" />
                        </div>
                        <div className="text-center">
                            <p className="text-xl font-bold text-zinc-300">Start your project</p>
                            <p className="text-sm text-zinc-500 mt-1">Upload images to begin adjusting</p>
                        </div>
                    </div>
                ) : (
                    <div 
                        className="grid gap-8 pb-32" 
                        style={{ 
                            gridTemplateColumns: `repeat(${data.gridColumns || 5}, minmax(0, 1fr))` 
                        }}
                    >
                        {sortedItems.map(item => (
                            <SingleIconCanvas 
                                key={item.id} 
                                item={item} 
                                data={data} 
                                isSelected={isItemSelected(item.id)}
                                onSelect={(e) => handleItemClick(item.id, e)}
                                onDelete={() => {
                                    const newItems = data.items.filter(i => i.id !== item.id);
                                    updateIconAdjusterData({ 
                                        items: newItems, 
                                        selectedItemIds: data.selectedItemIds.filter(sid => sid !== item.id) 
                                    });
                                }}
                            />
                        ))}
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};

export default IconAdjuster;

